from flask import Flask, request, jsonify
from flask_jwt_extended import JWTManager
from flask_sqlalchemy import SQLAlchemy

app = Flask(__name__)
app.config["JWT_SECRET_KEY"] = "your-secret-key"
jwt = JWTManager(app)
db = SQLAlchemy(app)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(120), unique=True, nullable=False)
    username = db.Column(db.String(80), unique=True, nullable=False)
    role = db.Column(db.String(80), nullable=False)
    account_status = db.Column(db.String(80), nullable=False)
    subscription_tier = db.Column(db.String(80), nullable=False)

@jwt.requires_roles("admin")
def update_user(user_id):
    user = User.query.get(user_id)
    if not user:
        return jsonify({"message": "User not found"}), 404

    data = request.get_json()
    for key, value in data.items():
        if key == "email":
            user.email = value
        elif key == "username":
            user.username = value
        elif key == "role":
            user.role = value
        elif key == "account_status":
            user.account_status = value
        elif key == "subscription_tier":
            user.subscription_tier = value

    db.session.commit()
    return jsonify({"message": "User updated successfully"}), 200